// Deep link parsed model
class DeepLinkData {
  final String scheme;
  final String host;
  final List<String> pathSegments;
  final Map<String, String> queryParameters;
  final String rawUri;

  DeepLinkData({
    required this.scheme,
    required this.host,
    required this.pathSegments,
    required this.queryParameters,
    required this.rawUri,
  });

  factory DeepLinkData.fromUri(Uri uri) {
    return DeepLinkData(
      scheme: uri.scheme,
      host: uri.host,
      pathSegments: uri.pathSegments.where((s) => s.isNotEmpty).toList(),
      queryParameters: uri.queryParameters,
      rawUri: uri.toString(),
    );
  }

  @override
  String toString() {
    return 'DeepLinkData(scheme: $scheme, host: $host, pathSegments: $pathSegments, queryParameters: $queryParameters)';
  }
}

// Route names
class AppRoutes {
  static const String home = '/';
  static const String profile = '/profile';
  static const String paymentConfirm = '/payment/confirm';
  static const String campaign = '/campaign';
  static const String notFound = '/not-found';
}

// Router
class AppRouter {
  static Route<dynamic> generateRoute(RouteSettings settings) {
    final uri = Uri.tryParse(settings.name ?? '');
    final args = settings.arguments;

    switch (settings.name) {
      case AppRoutes.home:
        return MaterialPageRoute(builder: (_) => const HomePage());

      case AppRoutes.profile:
        final profileId = args is Map ? args['profileId'] as String? : null;
        return MaterialPageRoute(
          builder: (_) => ProfilePage(profileId: profileId ?? 'unknown'),
        );

      case AppRoutes.paymentConfirm:
        final params = args is Map<String, dynamic> ? args : <String, dynamic>{};
        return MaterialPageRoute(
          builder: (_) => PaymentConfirmPage(params: params),
        );

      case AppRoutes.campaign:
        final params = args is Map<String, dynamic> ? args : <String, dynamic>{};
        return MaterialPageRoute(
          builder: (_) => CampaignPage(params: params),
        );

      default:
        return MaterialPageRoute(
          builder: (_) => NotFoundPage(route: settings.name),
        );
    }
  }
}

// Deep Link Handler Singleton
class DeepLinkHandler {
  static final GlobalKey<NavigatorState> navigatorKey =
      GlobalKey<NavigatorState>();

  static StreamSubscription<Uri?>? _linkSubscription;
  static bool _initialLinkHandled = false;

  /// Initialize deep link handling
  static Future<void> initialize() async {
    // Handle initial link (app opened from terminated state)
    await _handleInitialLink();

    // Handle incoming links while app is running
    _listenToIncomingLinks();
  }

  /// Dispose subscriptions
  static void dispose() {
    _linkSubscription?.cancel();
    _linkSubscription = null;
  }

  /// Handle the initial deep link that opened the app
  static Future<void> _handleInitialLink() async {
    if (_initialLinkHandled) return;
    _initialLinkHandled = true;

    try {
      final initialUri = await getInitialUri();
      if (initialUri != null) {
        debugPrint('[DeepLink] Initial link: $initialUri');
        _processUri(initialUri);
      }
    } catch (e) {
      debugPrint('[DeepLink] Error getting initial link: $e');
    }
  }

  /// Listen for incoming deep links while app is active
  static void _listenToIncomingLinks() {
    _linkSubscription?.cancel();
    _linkSubscription = uriLinkStream.listen(
      (Uri? uri) {
        if (uri != null) {
          debugPrint('[DeepLink] Incoming link: $uri');
          _processUri(uri);
        }
      },
      onError: (Object err) {
        debugPrint('[DeepLink] Error in link stream: $err');
      },
    );
  }

  /// Process and route the URI
  static void _processUri(Uri uri) {
    final deepLinkData = DeepLinkData.fromUri(uri);
    debugPrint('[DeepLink] Parsed: $deepLinkData');

    final navigator = navigatorKey.currentState;
    if (navigator == null) {
      debugPrint('[DeepLink] Navigator not available yet');
      // Retry after a short delay
      Future.delayed(const Duration(milliseconds: 500), () {
        _processUri(uri);
      });
      return;
    }

    _routeDeepLink(navigator, deepLinkData);
  }

  /// Route deep link to appropriate screen
  static void _routeDeepLink(
      NavigatorState navigator, DeepLinkData deepLinkData) {
    final host = deepLinkData.host;
    final segments = deepLinkData.pathSegments;
    final queryParams = deepLinkData.queryParameters;

    // myapp://profile/123 or myapp://profile?id=123
    if (host == 'profile') {
      String? profileId;
      if (segments.isNotEmpty) {
        profileId = segments.first;
      } else if (queryParams.containsKey('id')) {
        profileId = queryParams['id'];
      }

      navigator.pushNamed(
        AppRoutes.profile,
        arguments: {
          'profileId': profileId,
          ...queryParams,
        },
      );
      return;
    }

    // myapp://payment/confirm?txn_id=abc&amount=100&status=success
    if (host == 'payment' && segments.isNotEmpty && segments.first == 'confirm') {
      navigator.pushNamed(
        AppRoutes.paymentConfirm,
        arguments: {
          'transactionId': queryParams['txn_id'],
          'amount': queryParams['amount'],
          'status': queryParams['status'],
          'orderId': queryParams['order_id'],
          ...queryParams,
        },
      );
      return;
    }

    // myapp://campaign?name=summer_sale&source=push&medium=notification
    if (host == 'campaign') {
      navigator.pushNamed(
        AppRoutes.campaign,
        arguments: {
          'campaignName': queryParams['name'],
          'source': queryParams['source'],
          'medium': queryParams['medium'],
          'content': queryParams['content'],
          ...queryParams,
        },
      );
      return;
    }

    // myapp://home
    if (host == 'home') {
      navigator.pushNamedAndRemoveUntil(AppRoutes.home, (route) => false);
      return;
    }

    // Unknown deep link
    debugPrint('[DeepLink] Unhandled deep link: ${deepLinkData.rawUri}');
    navigator.pushNamed(
      AppRoutes.notFound,
      arguments: {'uri': deepLinkData.rawUri},
    );
  }
}

// Wrapper widget that initializes deep link handling
class DeepLinkWrapper extends StatefulWidget {
  const DeepLinkWrapper({super.key});

  @override
  State<DeepLinkWrapper> createState() => _DeepLinkWrapperState();
}

class _DeepLinkWrapperState extends State<DeepLinkWrapper> {
  @override
  void initState() {
    super.initState();
    // Initialize deep link handler after the first frame
    WidgetsBinding.instance.addPostFrameCallback((_) {
      DeepLinkHandler.initialize();
    });
  }

  @override
  void dispose() {
    DeepLinkHandler.dispose();
    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    return const HomePage();
  }
}

